using ArchStudy.Onion.Domain;
using ArchStudy.Shared.Dtos;

namespace ArchStudy.Onion.Application;

public class AccountAppService(
    IAccountRepository accounts,
    ITransactionRepository transactions,
    IUnitOfWork uow)
{
    public async Task<AccountResponse> CreateAsync(string owner, CancellationToken ct)
    {
        if (string.IsNullOrWhiteSpace(owner)) throw new ArgumentException("Owner required");
        var account = Account.Create(owner);
        await accounts.AddAsync(account, ct);
        await uow.SaveAsync(ct);
        return Map(account);
    }

    public async Task<AccountResponse?> GetAsync(Guid id, CancellationToken ct)
    {
        var account = await accounts.GetByIdAsync(id, ct);
        return account is null ? null : Map(account);
    }

    public async Task<IReadOnlyList<TransactionResponse>> GetStatementAsync(Guid id, CancellationToken ct)
    {
        var rows = await transactions.ListByAccountAsync(id, ct);
        return rows.Select(t => new TransactionResponse(t.Id, t.AccountId, t.Type, t.Amount, t.Timestamp, t.RelatedAccountId)).ToList();
    }

    public async Task<AccountResponse> DepositAsync(Guid id, decimal amount, CancellationToken ct)
    {
        var account = await accounts.GetByIdAsync(id, ct) ?? throw new KeyNotFoundException("Account not found");
        account.Deposit(amount);
        await transactions.AddAsync(Transaction.Create(account.Id, TransactionType.Deposit, amount), ct);
        await uow.SaveAsync(ct);
        return Map(account);
    }

    public async Task<AccountResponse> WithdrawAsync(Guid id, decimal amount, CancellationToken ct)
    {
        var account = await accounts.GetByIdAsync(id, ct) ?? throw new KeyNotFoundException("Account not found");
        account.Withdraw(amount);
        await transactions.AddAsync(Transaction.Create(account.Id, TransactionType.Withdrawal, amount), ct);
        await uow.SaveAsync(ct);
        return Map(account);
    }

    private static AccountResponse Map(Account a) => new(a.Id, a.Owner, a.Balance, a.CreatedAt);
}

public class TransferAppService(IAccountRepository accounts, ITransactionRepository transactions, IUnitOfWork uow)
{
    public async Task TransferAsync(Guid fromId, Guid toId, decimal amount, CancellationToken ct)
    {
        if (fromId == toId) throw new ArgumentException("Accounts must differ");
        var from = await accounts.GetByIdAsync(fromId, ct) ?? throw new KeyNotFoundException("Source account not found");
        var to = await accounts.GetByIdAsync(toId, ct) ?? throw new KeyNotFoundException("Destination account not found");

        from.Withdraw(amount);
        to.Deposit(amount);

        await transactions.AddAsync(Transaction.Create(from.Id, TransactionType.TransferOut, amount, to.Id), ct);
        await transactions.AddAsync(Transaction.Create(to.Id, TransactionType.TransferIn, amount, from.Id), ct);
        await uow.SaveAsync(ct);
    }
}

using ArchStudy.Onion.Domain;

namespace ArchStudy.Onion.Application;

public interface IAccountRepository
{
    Task<Account?> GetByIdAsync(Guid id, CancellationToken ct);
    Task AddAsync(Account account, CancellationToken ct);
}

public interface ITransactionRepository
{
    Task<IReadOnlyList<Transaction>> ListByAccountAsync(Guid accountId, CancellationToken ct);
    Task AddAsync(Transaction transaction, CancellationToken ct);
}

public interface IUnitOfWork
{
    Task SaveAsync(CancellationToken ct);
}

namespace ArchStudy.Onion.Domain;

public class Account
{
    public Guid Id { get; private set; }
    public string Owner { get; private set; } = string.Empty;
    public decimal Balance { get; private set; }
    public DateTime CreatedAt { get; private set; }

    private Account() { }

    public static Account Create(string owner) =>
        new()
        {
            Id = Guid.NewGuid(),
            Owner = owner,
            Balance = 0m,
            CreatedAt = DateTime.UtcNow,
        };

    public void Deposit(decimal amount)
    {
        if (amount <= 0) throw new ArgumentException("Amount must be positive");
        Balance += amount;
    }

    public void Withdraw(decimal amount)
    {
        if (amount <= 0) throw new ArgumentException("Amount must be positive");
        if (Balance < amount) throw new InvalidOperationException("Insufficient funds");
        Balance -= amount;
    }
}

using ArchStudy.Shared.Dtos;

namespace ArchStudy.Onion.Domain;

public class Transaction
{
    public Guid Id { get; private set; }
    public Guid AccountId { get; private set; }
    public TransactionType Type { get; private set; }
    public decimal Amount { get; private set; }
    public DateTime Timestamp { get; private set; }
    public Guid? RelatedAccountId { get; private set; }

    private Transaction() { }

    public static Transaction Create(Guid accountId, TransactionType type, decimal amount, Guid? related = null) =>
        new()
        {
            Id = Guid.NewGuid(),
            AccountId = accountId,
            Type = type,
            Amount = amount,
            Timestamp = DateTime.UtcNow,
            RelatedAccountId = related,
        };
}

using ArchStudy.Onion.Domain;
using Microsoft.EntityFrameworkCore;

namespace ArchStudy.Onion.Infrastructure;

public class OnionDbContext(DbContextOptions<OnionDbContext> options) : DbContext(options)
{
    public DbSet<Account> Accounts => Set<Account>();
    public DbSet<Transaction> Transactions => Set<Transaction>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Account>(b =>
        {
            b.HasKey(a => a.Id);
            b.Property(a => a.Owner).IsRequired();
            b.Property(a => a.Balance);
            b.Property(a => a.CreatedAt);
        });

        modelBuilder.Entity<Transaction>(b =>
        {
            b.HasKey(t => t.Id);
            b.Property(t => t.AccountId);
            b.Property(t => t.Type);
            b.Property(t => t.Amount);
            b.Property(t => t.Timestamp);
            b.Property(t => t.RelatedAccountId);
        });
    }
}

using ArchStudy.Onion.Application;
using ArchStudy.Onion.Domain;
using Microsoft.EntityFrameworkCore;

namespace ArchStudy.Onion.Infrastructure;

public class AccountRepository(OnionDbContext db) : IAccountRepository
{
    public Task<Account?> GetByIdAsync(Guid id, CancellationToken ct) =>
        db.Accounts.FirstOrDefaultAsync(a => a.Id == id, ct);

    public async Task AddAsync(Account account, CancellationToken ct) =>
        await db.Accounts.AddAsync(account, ct);
}

public class TransactionRepository(OnionDbContext db) : ITransactionRepository
{
    public async Task<IReadOnlyList<Transaction>> ListByAccountAsync(Guid accountId, CancellationToken ct) =>
        await db.Transactions
            .Where(t => t.AccountId == accountId)
            .OrderByDescending(t => t.Timestamp)
            .ToListAsync(ct);

    public async Task AddAsync(Transaction transaction, CancellationToken ct) =>
        await db.Transactions.AddAsync(transaction, ct);
}

public class UnitOfWork(OnionDbContext db) : IUnitOfWork
{
    public Task SaveAsync(CancellationToken ct) => db.SaveChangesAsync(ct);
}

using ArchStudy.Onion.Application;
using ArchStudy.Onion.Infrastructure;
using ArchStudy.Onion.Presentation;
using Microsoft.EntityFrameworkCore;

namespace ArchStudy.Onion;

public static class OnionModule
{
    public static IServiceCollection AddOnionModule(this IServiceCollection services)
    {
        services.AddDbContext<OnionDbContext>(o => o.UseSqlite("Data Source=archstudy-onion.db"));
        services.AddScoped<IAccountRepository, AccountRepository>();
        services.AddScoped<ITransactionRepository, TransactionRepository>();
        services.AddScoped<IUnitOfWork, UnitOfWork>();
        services.AddScoped<AccountAppService>();
        services.AddScoped<TransferAppService>();
        return services;
    }

    public static IEndpointRouteBuilder MapOnionModule(this IEndpointRouteBuilder routes)
    {
        var group = routes.MapGroup("/onion").WithTags("Onion");
        OnionEndpoints.Map(group);
        return routes;
    }

    public static async Task EnsureDatabaseCreatedAsync(IServiceProvider services)
    {
        var db = services.GetRequiredService<OnionDbContext>();
        await db.Database.EnsureCreatedAsync();
    }
}

using ArchStudy.Onion.Application;
using ArchStudy.Shared.Dtos;

namespace ArchStudy.Onion.Presentation;

public static class OnionEndpoints
{
    public static void Map(RouteGroupBuilder group)
    {
        group.MapPost("/accounts", async Task<IResult> (CreateAccountRequest req, AccountAppService svc, CancellationToken ct) =>
        {
            var account = await svc.CreateAsync(req.Owner, ct);
            return Results.Created($"/onion/accounts/{account.Id}", account);
        });

        group.MapGet("/accounts/{id:guid}", async Task<IResult> (Guid id, AccountAppService svc, CancellationToken ct) =>
        {
            var account = await svc.GetAsync(id, ct);
            return account is null ? Results.NotFound() : Results.Ok(account);
        });

        group.MapGet("/accounts/{id:guid}/transactions", async Task<IResult> (Guid id, AccountAppService svc, CancellationToken ct) =>
            Results.Ok(await svc.GetStatementAsync(id, ct)));

        group.MapPost("/accounts/{id:guid}/deposits", async Task<IResult> (Guid id, DepositRequest req, AccountAppService svc, CancellationToken ct) =>
            Results.Ok(await svc.DepositAsync(id, req.Amount, ct)));

        group.MapPost("/accounts/{id:guid}/withdrawals", async Task<IResult> (Guid id, WithdrawalRequest req, AccountAppService svc, CancellationToken ct) =>
            Results.Ok(await svc.WithdrawAsync(id, req.Amount, ct)));

        group.MapPost("/transfers", async Task<IResult> (TransferRequest req, TransferAppService svc, CancellationToken ct) =>
        {
            await svc.TransferAsync(req.FromAccountId, req.ToAccountId, req.Amount, ct);
            return Results.NoContent();
        });
    }
}
